.darma-loader-uiverse-minimal-arc {
  display: inline-block;
  width: 38px;
  height: 38px;
  border-radius: 50%;
  border: 3px solid color-mix(in srgb, var(--loader-color, #ef4444) 18%, transparent);
  border-left-color: var(--loader-color, #ef4444);
  animation: darma-loader-uiverse-minimal-arc-spin 0.7s linear infinite;
}
@keyframes darma-loader-uiverse-minimal-arc-spin { to { transform: rotate(360deg); } }

